def trimmed_mean(nums):
    if not nums:
        return None

    sorted_nums = sorted(nums)
    min_index, max_index = 1, len(sorted_nums) - 2
    if sorted_nums[0] == sorted_nums[1]:
        min_index = 0
    if sorted_nums[-1] == sorted_nums[-2]:
        max_index = len(sorted_nums) - 1

    return sum(sorted_nums[min_index:max_index]) / (len(sorted_nums[min_index:max_index]))
